27	int32_t riscv_nn_fc_mat_vec_s16_s16_s8_sft_bias_fast(const q15_t * in_vec,
28	                                    const q7_t * wt_mat,
29	                                    const uint16_t size,
30	                                    const uint16_t wt_row_num,
31	                                    const uint16_t bias_lshift,
32	                                    const uint16_t out_rshift,
33	                                    const q7_t * bias,
34	                                    q15_t * out_vec,
35	                                    q15_t * tmp_buf)
36	{
37	#ifdef ENA_EMPTY_FUN
38	    //empty body
39	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
40	    const q7_t *pB = wt_mat;
41	    const q7_t *pBias = bias;
42	    q15_t *pO = out_vec;
43	    const q15_t *pA;
44	    long vl;
45	    uint64_t rowCnt = wt_row_num >> 2;
46	    uint64_t colCnt = (size >> 1) << 3;
47	
48	    nn_dup_s16_x4_reordered_v2(in_vec, tmp_buf, size);
49	
50	    //generate acc reduction mask
51	    //Note. each element only occupy 1 bit
52	    const uint64_t base_mask = 0x1111111111111111;
53	    const uint64_t mask_1 = 0x1817161514111211;
54	    const uint64_t mask_2 = 0x1817161511131112;
55	    const uint64_t mask_3 = 0x1811171115141312;
56	    const uint64_t mask_4 = 0x1117111615141312;
57	    vl = __riscv_vsetvl_e64m8((colCnt+7)>>3);
58	    vuint64m2_t vBase_mask_u64 = __riscv_vmv_v_x_u64m2(base_mask, vl);
59	    vuint64m2_t vA1 = __riscv_vmv_v_x_u64m2(mask_1, vl);
60	    vuint64m2_t vA2 = __riscv_vmv_v_x_u64m2(mask_2, vl);
61	    vuint64m2_t vA3 = __riscv_vmv_v_x_u64m2(mask_3, vl);
62	    vuint64m2_t vA4 = __riscv_vmv_v_x_u64m2(mask_4, vl);
63	    vuint8m2_t vBase_interpret = __riscv_vreinterpret_v_u64m2_u8m2(vBase_mask_u64);
64	    vuint8m2_t vInterpret_1 = __riscv_vreinterpret_v_u64m2_u8m2(vA1);
65	    vuint8m2_t vInterpret_2 = __riscv_vreinterpret_v_u64m2_u8m2(vA2);
66	    vuint8m2_t vInterpret_3 = __riscv_vreinterpret_v_u64m2_u8m2(vA3);
67	    vuint8m2_t vInterpret_4 = __riscv_vreinterpret_v_u64m2_u8m2(vA4);
68	    vl = __riscv_vsetvl_e8m2(colCnt);
69	    vbool4_t vMask1_b4 = __riscv_vmseq(vBase_interpret, vInterpret_1, vl);   //8n   8n+1 index mask (for acc1)
70	    vbool4_t vMask2_b4 = __riscv_vmseq(vBase_interpret, vInterpret_2, vl);   //8n+2 8n+3 index mask (for acc2)
71	    vbool4_t vMask3_b4 = __riscv_vmseq(vBase_interpret, vInterpret_3, vl);   //8n+4 8n+5 index mask (for acc3)
72	    vbool4_t vMask4_b4 = __riscv_vmseq(vBase_interpret, vInterpret_4, vl);   //8n+6 8n+7 index mask (for acc4)
73	
74	    while (rowCnt)
75	    {
76	        // set SEW for 1st time VMV_S_X
77	        // LMUL=8 is just for clear acc (vmv ignores LMUL)
78	        vl = __riscv_vsetvl_e32m8(colCnt);
79	        //clear acc
80	        vint32m8_t vAcc_i32 = __riscv_vundefined_i32m8();

