22	#include "internal_nn_math.h"
23	
24	//// FullyConnected Functions
25	
26	int32_t riscv_nn_fc_mat_vec_s16_s16_s8_sft_bias(const q15_t * in_vec,
27	                                const q7_t * wt_mat,
28	                                const uint16_t size,
29	                                const uint16_t wt_row_num,
30	                                const uint16_t bias_lshift,
31	                                const uint16_t out_rshift,
32	                                const q7_t * bias,
33	                                q15_t * out_vec,
34	                                q15_t * tmp_buf)
35	{
36	#ifdef ENA_EMPTY_FUN
37	    //empty body
38	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
39	    long vl;
40	    long rowCnt = wt_row_num >> 1;
41	    const q15_t *in_vec_bak = in_vec;
42	
43	    while (rowCnt)
44	    {
45	        //clear v0~v15
46	        vl = __riscv_vsetvl_e32m8(size);
47	        vint32m8_t vAcc1_i32 = __riscv_vundefined_i32m8(),
48	                   vAcc2_i32 = __riscv_vundefined_i32m8();
49	        vAcc1_i32 = __riscv_vand(vAcc1_i32, 0, vl);
50	        vAcc2_i32 = __riscv_vand(vAcc2_i32, 0, vl);
51	
52	        in_vec = in_vec_bak;
53	        const q7_t *wt_mat2 = wt_mat + size;
54	        long colCnt2 = size;
55	
56	        while (colCnt2 > 0)
57	        {
58	            //load src2
59	            vl = __riscv_vsetvl_e8m2(colCnt2);
60	            vint8m2_t vWt_mat_i8 = __riscv_vle8_v_i8m2(wt_mat, vl);
61	            vint8m2_t vWt_mat2_i8 = __riscv_vle8_v_i8m2(wt_mat2, vl);
62	            //load src1
63	            vl = __riscv_vsetvl_e16m4(colCnt2);
64	            vint16m4_t vIn_vec_i16 = __riscv_vle16_v_i16m4(in_vec, vl);
65	            vint16m4_t vWt_mat_i16 = __riscv_vsext_vf2(vWt_mat_i8, vl);
66	            vint16m4_t vWt_mat2_i16 = __riscv_vsext_vf2(vWt_mat2_i8, vl);
67	            //acc += src1 * src2
68	            vAcc1_i32 = __riscv_vwmacc(vAcc1_i32, vIn_vec_i16, vWt_mat_i16, vl);
69	            vAcc2_i32 = __riscv_vwmacc(vAcc2_i32, vIn_vec_i16, vWt_mat2_i16, vl);
70	            //bump pointers and update loop counter
71	            colCnt2 -= vl;
72	            in_vec += vl;
73	            wt_mat += vl;
74	            wt_mat2 += vl;
75	        }
76	
77	        vl = __riscv_vsetvl_e32m1(size);
78	        vint32m1_t vZero_i32 = __riscv_vundefined_i32m1();
79	        vZero_i32 = __riscv_vand(vZero_i32, 0, vl);
80	        vl = __riscv_vsetvl_e32m8(size);

